func (engine *Engine) ServeHTTP(w http.ResponseWriter, req *http.Request) {
    engine.routeTreesUpdated.Do(func() { engine.updateRouteTrees() })

    c := engine.pool.Get().(*Context)
    c.writermem.reset(w)
    c.Request = req
    c.reset()                  // sets c.index = -1

    engine.handleHTTPRequest(c)
    engine.pool.Put(c)
}
```

### 5. `handleHTTPRequest` walks the radix tree and fires the chain

```go
